-- Migration 084 — populate empty content fields for all 109 products.
--
-- 0/109 products had how_to_use / ingredients / key_benefits / faq /
-- usage_tips populated post-WP-import. A research pass (Pakistani-English
-- tone, brand official pages for international SKUs, dvago/dawaai for
-- local supplements) generated content for every row. social_proof is
-- left as an empty string — merchant will hand-author testimonials.
--
-- Idempotent: WHERE clauses skip rows that already have non-empty values
-- so re-running won't clobber later admin edits.

WITH src AS (
  SELECT (j->>'id')::uuid                          AS id,
         NULLIF(j->>'how_to_use', '')              AS how_to_use,
         NULLIF(j->>'ingredients', '')             AS ingredients,
         (j->'key_benefits')                       AS key_benefits,
         (j->'faq')                                AS faq,
         NULLIF(j->>'usage_tips', '')              AS usage_tips,
         NULLIF(j->>'social_proof', '')            AS social_proof
    FROM jsonb_array_elements('[{"id":"0ba683b6-5823-4df4-b02e-ecc8f0ca1476","how_to_use":"Sweep across the high points of the face \u2014 cheekbones, brow bone, bridge of nose and cupid''s bow. Build gradually using a fan or fluffy brush for a soft glow, or pack on with a damp sponge for an intense highlight.","ingredients":"Talc, Mica, Synthetic Fluorphlogopite, Calcium Sodium Borosilicate, Magnesium Stearate, Boron Nitride, Dimethicone, Caprylic/Capric Triglyceride, Phenoxyethanol. May contain (+/-): Titanium Dioxide (CI 77891), Iron Oxides (CI 77491, CI 77492, CI 77499).","key_benefits":[{"icon":"\u2728","text":"Intense reflective highlight payoff"},{"icon":"\ud83c\udf38","text":"Smooth, buttery pressed powder formula"},{"icon":"\ud83d\udc9b","text":"Buildable from glow to glass-skin"},{"icon":"\ud83e\uddf4","text":"Stays put through long workdays"}],"faq":[{"q":"Will this look chalky on medium-deep Pakistani skin tones?","a":"Glow Seeker shades are designed with warm golden and rosy reflects that flatter wheatish to deep tones without going ashy."},{"q":"Can I use it as an eyeshadow?","a":"Yes \u2014 tap a little on the inner corners or lids for a glossy eye look."},{"q":"Is the product genuine?","a":"We source through verified channels \u2014 packaging, batch codes and PAO symbols are all original."}],"usage_tips":"Apply highlighter after foundation and blush but before setting spray for the most natural finish. Dampen your brush with a setting spray to intensify the shine for evening or wedding looks. Store away from direct sunlight to protect the pearl pigments.","social_proof":""},{"id":"90699631-4c4f-41ee-8d98-acd9092257ef","how_to_use":"Take one sachet dissolved in a glass of water once daily, preferably before a meal, or as directed by your physician. Drink immediately after mixing.","ingredients":"L-Arginine, L-Citrulline, Vitamin B complex, Folic Acid, Vitamin C. Multi-ingredient formulation; consult the package leaflet for the complete ingredient list and adult dosing instructions.","key_benefits":[{"icon":"\ud83d\udcaa","text":"Supports healthy blood flow"},{"icon":"\ud83c\udf3f","text":"Helps cardiovascular wellness"},{"icon":"\u26a1","text":"Boosts everyday energy levels"},{"icon":"\ud83d\udee1\ufe0f","text":"Aids endothelial function"}],"faq":[{"q":"When is the best time to take it?","a":"Most people take it in the morning before breakfast on an empty stomach, but follow your doctor''s advice."},{"q":"Are there any side effects?","a":"Generally well tolerated. Mild stomach upset can occur \u2014 discontinue and consult a doctor if it persists."},{"q":"Is it safe during pregnancy?","a":"Pregnant and breastfeeding women should consult their physician before use."}],"usage_tips":"Take consistently for at least 4\u20138 weeks to see steady cardiovascular benefits. Store in a cool, dry place away from direct sunlight. Pair with a balanced diet and regular light exercise for best results.","social_proof":""},{"id":"e7c99cce-e6a6-4431-ad93-2cd7a60ab780","how_to_use":"Empty one sachet into a glass of cold water, stir well and drink immediately once daily, or as advised by your doctor.","ingredients":"L-Arginine, L-Citrulline, B vitamins, Folic Acid. Multi-ingredient formulation; consult the package leaflet for the complete ingredient list and adult dosing instructions.","key_benefits":[{"icon":"\ud83d\udcaa","text":"Supports nitric oxide production"},{"icon":"\ud83c\udf3f","text":"Promotes healthy circulation"},{"icon":"\u26a1","text":"Helps maintain stamina"},{"icon":"\ud83d\udee1\ufe0f","text":"Supports heart health"}],"faq":[{"q":"Can men and women both take it?","a":"Yes, it is suitable for adult men and women unless contraindicated by a physician."},{"q":"How long until I feel a difference?","a":"Most users report noticeable energy and circulation benefits within 3\u20136 weeks of consistent use."},{"q":"Should it be taken with food?","a":"It is typically taken before meals, but if it upsets your stomach you can take it with food."}],"usage_tips":"Always mix with cold or room temperature water \u2014 hot liquids can degrade the amino acids. Keep the sachet sealed until ready to use. Maintain consistent daily intake for measurable cardiovascular support.","social_proof":""},{"id":"3b103617-e758-4cd7-8db0-5b6191d63184","how_to_use":"Wet your face, apply a small amount in gentle circular motions and rinse thoroughly with lukewarm water. Use morning and evening, or once daily if your skin feels sensitive.","ingredients":"Aqua/Water, Cocamidopropyl Hydroxysultaine, Glycerin, Salicylic Acid, Niacinamide, Ceramide NP, Ceramide AP, Ceramide EOP, Hyaluronic Acid, Cholesterol, Phytosphingosine, Xanthan Gum, Carbomer, Sodium Hydroxide, Tetrasodium EDTA, Disodium EDTA, Sodium Lauroyl Lactylate, Citric Acid, Phenoxyethanol, Ethylhexylglycerin.","key_benefits":[{"icon":"\ud83c\udf3f","text":"Salicylic acid clears clogged pores"},{"icon":"\ud83d\udca7","text":"Niacinamide calms redness"},{"icon":"\ud83d\udee1\ufe0f","text":"Ceramides protect skin barrier"},{"icon":"\ud83c\udf38","text":"Non-comedogenic and fragrance-free"}],"faq":[{"q":"Is it suitable for oily, acne-prone skin?","a":"Yes, this cleanser is specifically formulated for acne-prone skin and helps clear breakouts without stripping moisture."},{"q":"Can I use it daily?","a":"Yes \u2014 start once a day and build up to twice daily as your skin adjusts to the salicylic acid."},{"q":"Will it dry out my skin?","a":"It contains ceramides and hyaluronic acid to maintain hydration while clearing acne."}],"usage_tips":"Always follow with a non-comedogenic moisturiser and daily SPF \u2014 salicylic acid increases sun sensitivity. Avoid layering with other strong actives like retinol on the same night when starting out. Store away from direct sunlight.","social_proof":""},{"id":"3b9a7d32-32db-47ad-9b09-91c5bd2699b4","how_to_use":"Use the included CeraVe cleansers as part of your AM and PM routine \u2014 wet face, massage in gentle circles and rinse with lukewarm water. Follow with toner, treatment and moisturiser.","ingredients":"Bundle contains CeraVe cleansers \u2014 formulated with Ceramides, Hyaluronic Acid, Niacinamide and gentle surfactants. See individual product packaging for complete ingredient lists.","key_benefits":[{"icon":"\ud83d\udca7","text":"Hydrates while it cleanses"},{"icon":"\ud83d\udee1\ufe0f","text":"Supports the skin barrier"},{"icon":"\ud83c\udf3f","text":"Gentle, fragrance-free formulas"},{"icon":"\u2728","text":"Budget-friendly skincare combo"}],"faq":[{"q":"Which cleanser should I use first?","a":"If you double cleanse, use the Hydrating Cleanser in the morning and the stronger formula at night."},{"q":"Are these suitable for sensitive skin?","a":"Yes \u2014 CeraVe formulas are dermatologist-developed for sensitive and reactive skin."},{"q":"Is this an original bundle?","a":"Yes, all items in the bundle are original CeraVe products sourced through verified suppliers."}],"usage_tips":"Stick to one cleanser per session \u2014 over-cleansing can strip the barrier. Keep the bottles upright and away from heat. Pair with a moisturiser and SPF for the full CeraVe routine.","social_proof":""},{"id":"d03cd777-ca70-462e-918d-51ce1b85f548","how_to_use":"Apply liberally to face and body as often as needed, especially after a bath or shower while skin is still damp. Massage in until fully absorbed.","ingredients":"Purified Water, Glycerin, Caprylic/Capric Triglyceride, Cetearyl Alcohol, Ceteareth-20, Phenoxyethanol, Behentrimonium Methosulfate, Cetyl Alcohol, Polyglyceryl-3 Diisostearate, Potassium Phosphate, Ceramide NP, Ceramide AP, Ceramide EOP, Carbomer, Dimethicone, Dipotassium Phosphate, Sodium Lauroyl Lactylate, Disodium EDTA, Niacinamide, Cholesterol, Phytosphingosine, Xanthan Gum, Ethylhexylglycerin, Hyaluronic Acid, Sodium Hyaluronate, Tocopherol.","key_benefits":[{"icon":"\ud83d\udca7","text":"24-hour hydration with MVE technology"},{"icon":"\ud83d\udee1\ufe0f","text":"Restores protective skin barrier"},{"icon":"\ud83c\udf3f","text":"Fragrance-free, non-comedogenic"},{"icon":"\u2728","text":"Lightweight, non-greasy finish"}],"faq":[{"q":"Is it good for oily skin?","a":"Yes, the lightweight lotion absorbs quickly without clogging pores \u2014 great for oily and combination skin."},{"q":"Can I use it on my body?","a":"Absolutely \u2014 the 237 ml size is ideal for daily face and body moisturising."},{"q":"Does it work under makeup?","a":"Yes, it dries down to a soft non-greasy finish and works well as a base under foundation."}],"usage_tips":"Apply on damp skin within 3 minutes of cleansing to lock in maximum moisture. Layer a heavier cream on top in winter if your skin is very dry. Keep the bottle tightly closed to preserve potency.","social_proof":""},{"id":"2a42c24a-183b-4ea4-b64f-1d58df5354b5","how_to_use":"Cleanse morning and evening with the Hydrating Cleanser, then follow with the Moisturizing Cream \u2014 apply a pea-sized amount to face and neck and massage in. Use on body as needed.","ingredients":"Hydrating Cleanser: Ceramides, Hyaluronic Acid, Glycerin. Moisturizing Cream: Ceramides, Hyaluronic Acid, MVE delivery technology. See individual packaging for full ingredient lists.","key_benefits":[{"icon":"\ud83d\udca7","text":"Complete cleanse-and-moisturise routine"},{"icon":"\ud83d\udee1\ufe0f","text":"Strengthens skin barrier"},{"icon":"\ud83c\udf3f","text":"Suitable for dry and normal skin"},{"icon":"\u2728","text":"Budget-friendly duo"}],"faq":[{"q":"Is this bundle good for winter?","a":"Yes \u2014 the moisturising cream is rich and ideal for winter, while the cleanser is gentle enough not to strip skin."},{"q":"Will the cream feel heavy on oily skin?","a":"The cream is best for normal to dry skin. Oily skin types may prefer the Daily Moisturizing Lotion instead."},{"q":"Are the products fragrance-free?","a":"Yes, both items are fragrance-free and suitable for sensitive skin."}],"usage_tips":"Pat skin dry (don''t rub) before applying the cream so a touch of moisture stays on the surface. Use the cream on hands and elbows for extra dryness. Store at room temperature.","social_proof":""},{"id":"3513ff44-c54a-4128-a94f-20d583cb7137","how_to_use":"Apply to wet skin, massage gently in circular motions and rinse with lukewarm water. Use morning and night as the first step of your routine.","ingredients":"Aqua/Water, Glycerin, Behentrimonium Methosulfate, Cetearyl Alcohol, Phenoxyethanol, Stearyl Alcohol, Polyoxyl 40 Stearate, Glyceryl Stearate, Polysorbate 20, PEG-100 Stearate, Sodium Lauroyl Lactylate, Cetyl Alcohol, Hyaluronic Acid, Ceramide NP, Ceramide AP, Ceramide EOP, Carbomer, Disodium EDTA, Tetrasodium EDTA, Sodium Hydroxide, Niacinamide, Cholesterol, Phytosphingosine, Xanthan Gum, Tocopherol.","key_benefits":[{"icon":"\ud83d\udca7","text":"Hydrates as it cleanses"},{"icon":"\ud83d\udee1\ufe0f","text":"Protects skin barrier with ceramides"},{"icon":"\ud83c\udf3f","text":"Non-foaming, non-stripping formula"},{"icon":"\ud83c\udf38","text":"Suitable for sensitive skin"}],"faq":[{"q":"Is this cleanser good for dry skin?","a":"Yes \u2014 it is non-foaming and packed with ceramides and hyaluronic acid, perfect for dry and normal skin."},{"q":"Will it remove my makeup?","a":"It removes light makeup, but for heavy or waterproof makeup we recommend double-cleansing with an oil or balm first."},{"q":"Can it be used on the body too?","a":"Yes, it works well as a gentle body wash, especially for sensitive areas."}],"usage_tips":"Don''t expect a foam \u2014 this is a lotion-style cleanser that feels milky. Use lukewarm water to avoid irritating sensitive skin. Always follow with a moisturiser and daily SPF.","social_proof":""},{"id":"593a405a-d09f-446e-8de4-d31a0ce781cb","how_to_use":"Apply liberally on face and body as often as needed. Use morning and night, or any time skin feels dry, to lock in long-lasting hydration.","ingredients":"Purified Water, Glycerin, Caprylic/Capric Triglyceride, Behentrimonium Methosulfate, Cetyl Alcohol, Ceramide NP, Ceramide AP, Ceramide EOP, Hyaluronic Acid, Cholesterol, Petrolatum, Dimethicone, Phenoxyethanol, Disodium EDTA, Sodium Hyaluronate, Cetearyl Alcohol, Polyglyceryl-3 Diisostearate, Sodium Lauroyl Lactylate, Ethylhexylglycerin, Phytosphingosine, Xanthan Gum, Carbomer, Tocopherol.","key_benefits":[{"icon":"\ud83d\udca7","text":"Rich, long-lasting hydration"},{"icon":"\ud83d\udee1\ufe0f","text":"Restores compromised skin barrier"},{"icon":"\ud83c\udf3f","text":"Non-greasy, fragrance-free"},{"icon":"\ud83c\udf19","text":"Perfect overnight cream"}],"faq":[{"q":"Is the 340g jar original?","a":"Yes, sourced through verified channels with original batch coding."},{"q":"Can I use it on my baby''s skin?","a":"CeraVe Moisturizing Cream is gentle enough for sensitive and baby skin, but always patch test first."},{"q":"Will it break out oily skin?","a":"The cream is non-comedogenic. Oily skin types may still prefer the lighter Daily Lotion."}],"usage_tips":"Warm a scoop between your palms before applying so it spreads more easily. Use a spatula instead of fingers to keep the jar hygienic. Layer over a hyaluronic acid serum for an extra moisture boost.","social_proof":""},{"id":"d22228ce-cdc9-41a9-bf42-37ebb6be662b","how_to_use":"Smooth on face and body daily, morning and night. Massage in until absorbed and reapply whenever skin feels dry.","ingredients":"Purified Water, Glycerin, Caprylic/Capric Triglyceride, Cetearyl Alcohol, Ceramide NP, Ceramide AP, Ceramide EOP, Hyaluronic Acid, Cholesterol, Petrolatum, Dimethicone, Behentrimonium Methosulfate, Cetyl Alcohol, Phenoxyethanol, Disodium EDTA, Sodium Hyaluronate, Sodium Lauroyl Lactylate, Ethylhexylglycerin, Phytosphingosine, Xanthan Gum, Tocopherol.","key_benefits":[{"icon":"\ud83d\udca7","text":"Family-size 454g of hydration"},{"icon":"\ud83d\udee1\ufe0f","text":"Repairs skin barrier"},{"icon":"\ud83c\udf3f","text":"Fragrance-free, non-comedogenic"},{"icon":"\u2728","text":"Great value per gram"}],"faq":[{"q":"How long will the 454g tub last?","a":"With daily face and body use, the jar typically lasts 3\u20135 months for one person."},{"q":"Can the whole family use it?","a":"Yes \u2014 it is gentle enough for adults, teens and kids with sensitive or dry skin."},{"q":"Is it good for eczema-prone skin?","a":"CeraVe creams are dermatologist-recommended for eczema-prone and reactive skin types."}],"usage_tips":"Scoop with a clean spatula to keep the cream sanitary in a large jar. Use on hands and elbows after washing dishes or laundry to prevent cracking. Keep tightly sealed away from heat.","social_proof":""},{"id":"45a45377-558f-4459-bfbd-7321441a0d87","how_to_use":"After your moisturiser, apply a generous amount to face and exposed areas as the last step of your morning routine. Reapply every 2 hours during sun exposure.","ingredients":"Active: Homosalate, Octisalate, Octocrylene, Avobenzone. Other: Water, Niacinamide, Ceramides (NP, AP, EOP), Hyaluronic Acid, Iron Oxides for sheer tint, Glycerin, Dimethicone, Tocopherol.","key_benefits":[{"icon":"\u2600\ufe0f","text":"Broad spectrum SPF 30 protection"},{"icon":"\ud83c\udf38","text":"Sheer universal tint blurs skin"},{"icon":"\ud83d\udca7","text":"Hyaluronic acid + ceramides hydrate"},{"icon":"\ud83d\udee1\ufe0f","text":"Non-comedogenic, fragrance-free"}],"faq":[{"q":"Will the tint match Pakistani skin tones?","a":"The sheer universal tint is designed to blur, not match \u2014 it works on fair to deep tones without leaving a white cast."},{"q":"Can I wear it under foundation?","a":"Yes, it works beautifully as a primer-tint hybrid under foundation or concealer."},{"q":"Is it suitable for sensitive skin?","a":"Yes, the formula is fragrance-free and dermatologist-tested for sensitive skin."}],"usage_tips":"Use at least two finger-lengths for full face coverage to get the labelled SPF protection. Reapply throughout the day, especially before stepping out. Shake gently before each use.","social_proof":""},{"id":"af650c00-e62a-4b2a-b034-6203371f299d","how_to_use":"Cleanse with the CeraVe cleanser AM and PM, then in the morning finish your routine with the sunscreen as the final step. Reapply sunscreen every 2 hours in the sun.","ingredients":"Cleanser: Ceramides, Hyaluronic Acid, Niacinamide. Sunscreen: SPF filters with Ceramides and Niacinamide. See each product''s packaging for the full ingredient list.","key_benefits":[{"icon":"\u2600\ufe0f","text":"Daily sun protection routine"},{"icon":"\ud83d\udca7","text":"Cleanses without stripping moisture"},{"icon":"\ud83d\udee1\ufe0f","text":"Reinforces the skin barrier"},{"icon":"\u2728","text":"Two essentials at bundle price"}],"faq":[{"q":"Is the sunscreen tinted or clear?","a":"Depends on the bundle variant \u2014 check the product image. Tinted versions blur and even-out without a white cast."},{"q":"Is this enough for a daily routine?","a":"It covers cleansing and SPF \u2014 pair with a moisturiser for a complete routine."},{"q":"Are both products original?","a":"Yes, both items are 100% original CeraVe sourced through verified channels."}],"usage_tips":"Apply sunscreen 15 minutes before stepping out so it has time to settle. Use two-finger lengths of SPF for full face protection. Keep the bottles upright and away from heat to maintain formula stability.","social_proof":""},{"id":"af3dd5cc-27e6-4943-8da0-1ca421e38e9e","how_to_use":"Sweep a fluffy brush across the powder and dust over high points of the face for a soft highlight or all over for a baked finish. Build up gradually for a more intense glow.","ingredients":"Talc, Mica, Magnesium Stearate, Dimethicone, Phenoxyethanol, Methylparaben, Propylparaben. May contain (+/-): Iron Oxides (CI 77491, CI 77492, CI 77499), Titanium Dioxide (CI 77891).","key_benefits":[{"icon":"\u2728","text":"Soft baked-powder highlight"},{"icon":"\ud83c\udf38","text":"Lightweight, blendable finish"},{"icon":"\ud83d\udc9b","text":"Warm shade flattering for desi skin"},{"icon":"\ud83e\uddf4","text":"Affordable everyday glow"}],"faq":[{"q":"Is shade 828 suitable for medium skin?","a":"Yes, 828 is a warm shade that complements wheatish to medium Pakistani skin tones."},{"q":"Can I use it as a setting powder?","a":"Best used as a highlighter or to add warmth \u2014 for setting use a translucent powder underneath."},{"q":"Is it long-lasting?","a":"Set with a setting spray for all-day wear, especially in humid weather."}],"usage_tips":"Tap excess powder off the brush before applying to avoid fallout. Layer over a cream highlighter for an extra dewy effect. Keep the compact closed tightly to protect from moisture.","social_proof":""},{"id":"2ebff7eb-e0bd-47be-9f56-6ee30993cdfc","how_to_use":"Choose one of the four shades to suit your look. Use a fan or fluffy brush to dust along cheekbones, brow bone, nose bridge and cupid''s bow.","ingredients":"Talc, Mica, Magnesium Stearate, Dimethicone, Phenoxyethanol, May contain (+/-) Mica, Iron Oxides (CI 77491, CI 77492, CI 77499), Titanium Dioxide (CI 77891), Carmine (CI 75470).","key_benefits":[{"icon":"\u2728","text":"Four shades for every mood"},{"icon":"\ud83c\udf38","text":"Buttery, blendable formula"},{"icon":"\ud83d\udc9b","text":"Suits fair to deep skin"},{"icon":"\ud83e\uddf4","text":"Travel-friendly palette"}],"faq":[{"q":"Can the shades be mixed?","a":"Yes \u2014 swirl two shades together to create a custom highlight."},{"q":"Is the shimmer chunky?","a":"No, it has a fine, refined shimmer suitable for everyday wear."},{"q":"Is it suitable for the bridge of nose and inner corners of eyes?","a":"Absolutely \u2014 the fine texture works beautifully on smaller areas too."}],"usage_tips":"Use a smaller brush for precise placement on the nose bridge and brow bone. Apply after blush so the shimmer sits cleanly. Keep the palette closed to prevent dust contamination.","social_proof":""},{"id":"da400ba0-da3b-422c-a940-50325f4115a4","how_to_use":"Prime the lids first, then pick up colour with a flat shader brush and pat onto the lid. Use a fluffy brush to blend transition shades into the crease. Finish with a dark or shimmer shade on the outer corner.","ingredients":"Talc, Mica, Magnesium Stearate, Caprylic/Capric Triglyceride, Phenoxyethanol, Tocopheryl Acetate. May contain (+/-): Iron Oxides, Titanium Dioxide, Carmine, Manganese Violet, Ultramarines, Chromium Oxide Greens.","key_benefits":[{"icon":"\u2728","text":"28 versatile mattes and shimmers"},{"icon":"\ud83c\udf38","text":"Velvety, blendable pigments"},{"icon":"\ud83d\udc9b","text":"Mix of warm and cool tones"},{"icon":"\ud83e\uddf4","text":"Great value for beginners"}],"faq":[{"q":"Are the shadows highly pigmented?","a":"Yes \u2014 most shades are buildable with one or two layers; spray the brush with setting spray for intense pigment."},{"q":"Will the shimmers fall out?","a":"Use a sticky base or damp brush to minimise fallout."},{"q":"Is it good for beginners?","a":"Yes, the wide range of shades makes it ideal for experimenting with eye looks."}],"usage_tips":"Use a primer or concealer base to make colours pop and last longer. Tap excess pigment off the brush before applying. Keep the palette closed and dry \u2014 broken shadows can be pressed back with a few drops of rubbing alcohol.","social_proof":""},{"id":"458c9d63-79ab-41ce-8b63-80b0d52c85c2","how_to_use":"Sweep a fluffy brush over the powder and tap onto the apples of the cheeks, blending up toward the temples. Build colour gradually for a soft flush or layered glow.","ingredients":"Talc, Mica, Magnesium Stearate, Octyldodecyl Stearoyl Stearate, Synthetic Fluorphlogopite, Silica, Dimethicone, Phenoxyethanol, Tocopherol. May contain (+/-): Iron Oxides (CI 77491, CI 77492, CI 77499), Carmine (CI 75470), Titanium Dioxide (CI 77891).","key_benefits":[{"icon":"\ud83c\udf38","text":"Iconic rosy radiant flush"},{"icon":"\u2728","text":"Pearl finish for a healthy glow"},{"icon":"\ud83d\udc9b","text":"Long-lasting buildable colour"},{"icon":"\ud83e\uddf4","text":"Luxury Dior compact"}],"faq":[{"q":"Will Rosy Glow work on warm Pakistani skin?","a":"Yes \u2014 the heat-activated formula adapts to your skin''s pH for a personalised rosy flush."},{"q":"Is it matte or shimmery?","a":"It has a soft pearl finish, not glittery, giving a healthy lit-from-within look."},{"q":"Is the packaging original Dior?","a":"Yes, we source only authentic Dior products with original batch coding."}],"usage_tips":"Smile and apply on the apples of the cheeks for a youthful finish. Layer over a cream blush for extra longevity in summer. Store the compact closed to protect the delicate pearl powder.","social_proof":""},{"id":"2a7f30fb-0e3d-453a-a501-c1ed840f95e1","how_to_use":"Shake well, then apply a thin even layer to clean dry skin as the last step of your morning routine. Use fingers or a damp sponge to blend. Reapply every 2 hours in the sun.","ingredients":"Active: Octinoxate 7.5%, Zinc Oxide 9%. Other: Water, Glycerin, Niacinamide, Hyaluronic Acid, Caprylyl Methicone, Iron Oxides, Tocopheryl Acetate, Dimethicone, Phenoxyethanol.","key_benefits":[{"icon":"\u2600\ufe0f","text":"Broad spectrum SPF 46"},{"icon":"\ud83c\udf38","text":"Universal tint blurs imperfections"},{"icon":"\ud83d\udca7","text":"Hyaluronic acid + niacinamide hydrate"},{"icon":"\ud83d\udee1\ufe0f","text":"Sensitive-skin friendly"}],"faq":[{"q":"Does it leave a white cast?","a":"No \u2014 the universal tint blurs and adapts, with no white or grey cast on medium-deep skin."},{"q":"Can it replace foundation?","a":"Yes, many users wear it alone for a no-makeup makeup look with sun protection."},{"q":"Is it water resistant?","a":"It offers light water resistance \u2014 reapply after sweating or swimming."}],"usage_tips":"Apply about two finger-lengths for full face SPF protection. Layer concealer over spots instead of more sunscreen. Keep upright and away from heat to prevent separation.","social_proof":""},{"id":"b251884d-bd85-46d8-96d0-46b09ed0cf91","how_to_use":"Swirl a fluffy brush into the jelly-powder and dust over cheekbones, brow bone and shoulders. For extreme intensity, pat onto skin with a damp fingertip or sponge.","ingredients":"Synthetic Fluorphlogopite, Caprylic/Capric Triglyceride, Polybutene, Octyldodecanol, Glyceryl Caprylate, Tocopheryl Acetate, Sorbitan Sesquiisostearate, Tin Oxide, Calcium Sodium Borosilicate, Silica, May contain (+/-) Mica, Titanium Dioxide, Iron Oxides.","key_benefits":[{"icon":"\u2728","text":"Intense, blinding glass highlight"},{"icon":"\ud83c\udf38","text":"Jelly-powder hybrid texture"},{"icon":"\ud83d\udc9b","text":"Buildable from glow to bling"},{"icon":"\ud83e\uddf4","text":"Cult Fenty favourite"}],"faq":[{"q":"Is the glitter chunky?","a":"Diamond Bomb has visible reflective flakes \u2014 perfect for nights out and weddings, dial down for daytime."},{"q":"How do I apply without fallout?","a":"Use a fingertip or damp brush rather than a dry brush for maximum stick and minimum fallout."},{"q":"Will it work on deep skin tones?","a":"Yes \u2014 Fenty''s Diamond Bomb is designed to look stunning across the full shade range."}],"usage_tips":"Use a setting spray on the brush for extra intensity. Apply after powder so the shimmer doesn''t disturb foundation. Close the pan tightly \u2014 the jelly can dry out if exposed.","social_proof":""},{"id":"9576cb74-b6f5-4b79-b6c0-11ea9e933b3e","how_to_use":"Twist up the stick and swipe directly on lips and cheeks. Blend with fingers for a soft, natural flush of colour and shine.","ingredients":"Caprylic/Capric Triglyceride, Hydrogenated Polyisobutene, Citrullus Lanatus (Watermelon) Fruit Extract, Hibiscus Sabdariffa Flower Extract, Glycerin, Tocopherol, Squalane, Aroma, Sorbitan Olivate. May contain (+/-): Iron Oxides, Carmine, Mica.","key_benefits":[{"icon":"\ud83c\udf38","text":"Lip and cheek 2-in-1"},{"icon":"\ud83d\udca7","text":"Watermelon extract hydrates"},{"icon":"\u2728","text":"Soft natural-flush colour"},{"icon":"\ud83e\uddf4","text":"Pocket-sized for touch-ups"}],"faq":[{"q":"Is it sticky on lips?","a":"No, the balm-like formula is comfortable and non-sticky, great for everyday wear."},{"q":"Will the colour show on darker lips?","a":"It gives a sheer-to-medium flush \u2014 for more pigment, layer it a few times."},{"q":"Is it scented?","a":"Yes, it has a light fruity watermelon scent without strong added fragrance."}],"usage_tips":"Apply on cheeks first while the formula is fresh and blend quickly. Top with a lip balm for an extra glossy finish. Store at room temperature to keep the stick firm.","social_proof":""},{"id":"ba481798-5ee1-463c-a846-6ec7b33fa1f3","how_to_use":"Outline lips with the doe-foot applicator, then fill in. Let the formula set for 30\u201360 seconds for a fully matte, long-wear finish.","ingredients":"Isododecane, Dimethicone, Trimethylsiloxysilicate, Disteardimonium Hectorite, Polypropylsilsesquioxane, Tocopheryl Acetate, Phenoxyethanol. May contain (+/-): Iron Oxides, Titanium Dioxide, Red 7 Lake, Red 6 Lake, Carmine.","key_benefits":[{"icon":"\ud83d\udc9b","text":"Long-wear matte finish"},{"icon":"\u2728","text":"Highly pigmented colour payoff"},{"icon":"\ud83e\uddf4","text":"Comfortable, non-drying formula"},{"icon":"\ud83c\udf38","text":"Range of wearable shades"}],"faq":[{"q":"Is it drying on lips?","a":"Huda''s Icon Liquid Lipstick is designed to be comfortable, not drying \u2014 but use a lip balm underneath if your lips are very dry."},{"q":"How long does it last?","a":"Most users get 6\u20138 hours of wear; expect light fading after eating oily food."},{"q":"Will it transfer to a cup or mask?","a":"Minimal transfer once fully set \u2014 wait at least a minute before drinking."}],"usage_tips":"Exfoliate lips gently before applying for the smoothest finish. Don''t press lips together while wet \u2014 it can cause patchiness. Touch up edges with a Q-tip dipped in concealer.","social_proof":""},{"id":"ddfb3534-02c2-4d5a-9048-26d8be3f2120","how_to_use":"Dot a small amount onto cheekbones, brow bone and cupid''s bow using the doe-foot applicator. Tap and blend with fingertip or a damp sponge for a liquid-glass finish.","ingredients":"Cyclopentasiloxane, Synthetic Fluorphlogopite, Dimethicone, Polybutene, Trimethylsiloxysilicate, Squalane, Tocopheryl Acetate, Phenoxyethanol. May contain (+/-): Mica, Titanium Dioxide, Iron Oxides.","key_benefits":[{"icon":"\u2728","text":"Intense liquid highlighter glow"},{"icon":"\ud83c\udf38","text":"Buildable from sheer to blinding"},{"icon":"\ud83d\udc9b","text":"Beautiful shades for desi skin"},{"icon":"\ud83e\uddf4","text":"Travel-friendly tube"}],"faq":[{"q":"Can I mix it with foundation?","a":"Yes \u2014 mix a drop into your foundation for an all-over glowy finish."},{"q":"Is it long-lasting?","a":"Apply before powder and set lightly with setting spray for all-day glow."},{"q":"Is the shimmer visible on darker skin?","a":"Iconic London''s shades are deeply pigmented and show beautifully on medium and deep skin tones."}],"usage_tips":"Apply with fingers warmed from body heat to melt the formula into skin. Don''t pile on too many layers \u2014 a little goes a long way. Replace the cap tightly to avoid the product drying out.","social_proof":""},{"id":"9ca05632-50b9-444c-b33c-d907456b43ef","how_to_use":"Apply directly to lips using the doe-foot applicator. Layer for more shine and intensity. Use over a lipstick for a glossy finish or alone for a plump-look.","ingredients":"Polybutene, Hydrogenated Polyisobutene, Octyldodecanol, Synthetic Fluorphlogopite, Hyaluronic Acid, Tocopheryl Acetate, Mica, Silica. May contain (+/-): Titanium Dioxide, Iron Oxides, Carmine.","key_benefits":[{"icon":"\ud83d\udca7","text":"Hyaluronic acid plumps lips"},{"icon":"\u2728","text":"High-shine 3D glossy finish"},{"icon":"\ud83c\udf38","text":"Non-sticky comfortable formula"},{"icon":"\ud83e\uddf4","text":"Affordable Italian beauty brand"}],"faq":[{"q":"Will my lips plump after use?","a":"Yes \u2014 hyaluronic acid gives a subtle plumping effect with consistent use."},{"q":"Is it sticky?","a":"No, this gloss is comfortable and non-sticky, even when layered."},{"q":"Can I wear it over lipstick?","a":"Absolutely \u2014 it adds dimension and shine over any matte lipstick."}],"usage_tips":"Apply to the centre of the lips and press lips together for a juicy puffy look. Keep the wand clean to avoid contamination. Store away from heat to preserve the slick texture.","social_proof":""},{"id":"77f74934-2930-4cec-866f-f7229e824f6d","how_to_use":"Shake well, dispense a pump onto the back of your hand and apply to the centre of the face using fingers, a brush or damp sponge. Blend outward and build for medium-to-full coverage.","ingredients":"Aqua/Water, Cyclopentasiloxane, Glycerin, Dimethicone, PEG-10 Dimethicone, Phenyl Trimethicone, Disteardimonium Hectorite, Tocopheryl Acetate, Sodium Hyaluronate, Phenoxyethanol. May contain (+/-): Iron Oxides, Titanium Dioxide.","key_benefits":[{"icon":"\ud83c\udf38","text":"Medium-to-full buildable coverage"},{"icon":"\u2728","text":"Long-wearing natural finish"},{"icon":"\ud83d\udca7","text":"Lightweight, breathable formula"},{"icon":"\ud83e\uddf4","text":"Wide shade range"}],"faq":[{"q":"Is shade 5.5 Gold good for medium Pakistani skin?","a":"Yes, 5.5 Gold is a warm medium with golden undertones that flatters wheatish to tan skin beautifully."},{"q":"Is it matte or dewy?","a":"It dries down to a natural semi-matte finish \u2014 set with powder for full matte or skip powder for soft glow."},{"q":"Will it cover acne and dark spots?","a":"Yes, the buildable formula offers medium coverage that can be layered for blemishes."}],"usage_tips":"Press onto skin rather than dragging for the cleanest finish. Use a damp sponge for a more skin-like effect. Shake the bottle well before each use to mix the pigments evenly.","social_proof":""},{"id":"3ba0611e-740d-42fe-ae97-b75463f7501f","how_to_use":"Dot a small amount on each cheek and blend quickly with fingers, a sponge or a stippling brush before it sets. Build colour gradually.","ingredients":"Aqua/Water, Glycerin, Caprylic/Capric Triglyceride, Squalane, Sodium Hyaluronate, Cetearyl Alcohol, Phenoxyethanol, Tocopheryl Acetate. May contain (+/-): Iron Oxides, Carmine, Titanium Dioxide.","key_benefits":[{"icon":"\ud83d\udca7","text":"Dewy hydrated finish"},{"icon":"\ud83c\udf38","text":"Highly pigmented liquid blush"},{"icon":"\u2728","text":"Blends seamlessly into skin"},{"icon":"\ud83e\uddf4","text":"Affordable luxe alternative"}],"faq":[{"q":"How pigmented is it?","a":"Very pigmented \u2014 a small dot per cheek is enough, so go slow when blending."},{"q":"Is it sticky on cheeks?","a":"No, it sets to a dewy second-skin finish that feels weightless."},{"q":"Will it work on oily skin?","a":"Yes \u2014 set lightly with powder after blending for longer wear on oily skin."}],"usage_tips":"Apply before powder for the smoothest blend. Use one dot per cheek; you can always build more. Cap the bottle tightly to keep the formula from drying out.","social_proof":""},{"id":"101e706e-90b8-4d07-9c34-538422688f49","how_to_use":"Dispense a small amount onto the back of your hand or directly onto cheeks. Blend immediately with fingertips, a damp sponge or a brush for a luminous flush.","ingredients":"Aqua/Water, Glycerin, Dimethicone, Caprylic/Capric Triglyceride, Synthetic Fluorphlogopite, Hyaluronic Acid, Tocopheryl Acetate, Phenoxyethanol. May contain (+/-): Mica, Iron Oxides, Carmine, Titanium Dioxide.","key_benefits":[{"icon":"\u2728","text":"Luminous, lit-from-within finish"},{"icon":"\ud83d\udca7","text":"Hyaluronic acid adds hydration"},{"icon":"\ud83c\udf38","text":"Buildable pigment payoff"},{"icon":"\ud83e\uddf4","text":"Iconic NARS quality"}],"faq":[{"q":"What''s the difference between Orgasm and Afterglow?","a":"Afterglow has more luminosity and hydration; Orgasm liquid is slightly more sheer and natural."},{"q":"Will it work on mature skin?","a":"Yes, the liquid formula doesn''t sit in pores or lines and gives a youthful flush."},{"q":"How long does it last?","a":"Expect 6\u20138 hours of wear, especially when layered over a creamy base."}],"usage_tips":"Pump or shake before dispensing \u2014 pigments can settle. Apply on bare skin or over foundation, but before powder. Cap tightly and store upright.","social_proof":""},{"id":"ed57e391-4783-480c-a126-432e3bd407dd","how_to_use":"Shake well, then pump onto the back of your hand. Apply with a damp sponge or buffing brush to the centre of the face and blend outward. Use over moisturiser and SPF.","ingredients":"Aqua/Water, Cyclopentasiloxane, Glycerin, Dimethicone, Light-reflecting pigments, Hyaluronic Acid, Bambusa Vulgaris Extract, Tocopheryl Acetate, Phenoxyethanol. May contain (+/-): Iron Oxides, Titanium Dioxide.","key_benefits":[{"icon":"\u2728","text":"Photochromic light-adjusting finish"},{"icon":"\ud83d\udca7","text":"Hyaluronic acid hydrates"},{"icon":"\ud83c\udf38","text":"Skin-like medium coverage"},{"icon":"\ud83e\uddf4","text":"Full shade range available"}],"faq":[{"q":"Which shade should I pick for Pakistani skin?","a":"Shades like Mont Blanc, Stromboli, Punjab, Huahine and Macao work for fair to deep desi skin \u2014 check our shade guide or message us."},{"q":"Is it good for oily skin?","a":"Yes, set with a light powder on the T-zone for extended wear."},{"q":"Does it look heavy?","a":"No \u2014 the formula is light and skin-like with a soft luminous finish, not cakey."}],"usage_tips":"Apply on slightly damp skin for the most flattering finish. Use a sponge to press the formula in for a skin-like effect. Less is more \u2014 start with one pump and build.","social_proof":""},{"id":"bec48b6e-0d7d-4e40-9a96-4acc592d2e24","how_to_use":"Pump onto the back of your hand, then apply to the centre of the face with a damp sponge or brush and blend outward. Build coverage as needed.","ingredients":"Aqua/Water, Cyclopentasiloxane, Glycerin, Dimethicone, Hyaluronic Acid, Light-reflecting pigments, Bambusa Vulgaris Extract, Tocopheryl Acetate, Phenoxyethanol. May contain (+/-): Iron Oxides, Titanium Dioxide.","key_benefits":[{"icon":"\u2728","text":"Mont Blanc \u2014 fair with cool undertones"},{"icon":"\ud83d\udca7","text":"Hydrating light-reflecting formula"},{"icon":"\ud83c\udf38","text":"Medium buildable coverage"},{"icon":"\ud83e\uddf4","text":"Original NARS quality"}],"faq":[{"q":"Is Mont Blanc fair or medium?","a":"Mont Blanc is one of NARS''s fairest shades, with cool/neutral undertones \u2014 best for very light skin."},{"q":"Will it oxidise to a darker shade?","a":"NARS Light Reflecting Foundations are designed to minimise oxidation, but always test before committing."},{"q":"Can it be mixed with another shade?","a":"Yes \u2014 mixing two pumps lets you customise the perfect shade for your skin."}],"usage_tips":"Always apply on moisturised skin so the formula glides on smoothly. Use a damp sponge to press in rather than drag. Store away from direct light to maintain pigment stability.","social_proof":""},{"id":"14c9fd35-0128-4bf0-a86e-f37bdd8b109e","how_to_use":"Apply Tarte Shape Tape concealer under the eyes and on blemishes; blend with a sponge. Then dot NARS Orgasm blush onto cheeks and blend out for a flush of peachy-pink with golden shimmer.","ingredients":"Tarte Shape Tape: Water, Cyclopentasiloxane, Mica, Hyaluronic Acid, Vitamin E. NARS Orgasm Blush: Talc, Mica, Magnesium Stearate, Iron Oxides, Carmine. See packaging for full lists.","key_benefits":[{"icon":"\u2728","text":"Cult-favourite blush + concealer duo"},{"icon":"\ud83c\udf38","text":"Iconic peachy-pink Orgasm flush"},{"icon":"\ud83d\udca7","text":"Full-coverage crease-free concealer"},{"icon":"\ud83e\uddf4","text":"Bundle saving on two essentials"}],"faq":[{"q":"Is shade 29N right for medium Pakistani skin?","a":"29N is light-medium with neutral undertones \u2014 great for fair to wheatish skin. Check the shade chart if you''re darker."},{"q":"Is Orgasm too pink for my skin?","a":"Orgasm has a universally flattering peachy-pink with gold shimmer that suits a wide range of skin tones."},{"q":"Are both products original?","a":"Yes \u2014 sourced through verified channels with original packaging and batch codes."}],"usage_tips":"Tap concealer with a sponge instead of dragging to avoid creasing. Apply blush after powder for a smooth blend. Keep both products tightly closed to maintain freshness.","social_proof":""},{"id":"3aaa7903-40bc-47b1-a96b-49326d152c0e","how_to_use":"Swirl a fluffy brush across both blush and bronzer, then dust over cheeks for a sun-kissed flushed look. Apply bronzer on temples, jawline and forehead, and blush on the apples of cheeks.","ingredients":"Talc, Mica, Magnesium Stearate, Caprylic/Capric Triglyceride, Tocopheryl Acetate, Phenoxyethanol. May contain (+/-): Iron Oxides, Titanium Dioxide, Mica.","key_benefits":[{"icon":"\u2600\ufe0f","text":"Bronze + blush in one pan"},{"icon":"\u2728","text":"Soft glowy buildable finish"},{"icon":"\ud83c\udf38","text":"Travel-friendly duo"},{"icon":"\ud83e\uddf4","text":"Suits a range of skin tones"}],"faq":[{"q":"Will the bronzer look orange on fair skin?","a":"Pixi''s bronzer leans warm-neutral and blends out beautifully on fair to medium skin without muddiness."},{"q":"Can I use the blush on lips?","a":"It''s not designed for lips, but a tiny amount mixed with balm can give a soft tint."},{"q":"Is the compact small enough to carry?","a":"Yes \u2014 slim and pocket-friendly, perfect for touch-ups on the go."}],"usage_tips":"Use a small brush for precise bronzer placement on the hollows of cheeks. Build slowly \u2014 a little goes a long way. Keep the mirror clean and the compact closed to prevent breakage.","social_proof":""},{"id":"1713b416-f4e4-4dd9-8849-70317309240b","how_to_use":"Apply blush on the apples of the cheeks with a fluffy brush, then sweep highlighter along cheekbones, brow bone, and cupid''s bow. Build for desired intensity.","ingredients":"Talc, Mica, Magnesium Stearate, Caprylic/Capric Triglyceride, Synthetic Fluorphlogopite, Tocopheryl Acetate, Phenoxyethanol. May contain (+/-): Iron Oxides, Titanium Dioxide, Mica.","key_benefits":[{"icon":"\ud83c\udf38","text":"Blush + highlighter combo"},{"icon":"\u2728","text":"Glowing radiant finish"},{"icon":"\ud83d\udc9b","text":"Beautifully buildable pigments"},{"icon":"\ud83e\uddf4","text":"Pocket-friendly Pixi duo"}],"faq":[{"q":"Is the highlighter chunky?","a":"No, it''s a finely-milled pearl highlight suitable for everyday wear."},{"q":"Will the blush show on deeper skin tones?","a":"Yes, Pixi''s blush shades are warm and pigmented enough to show on a range of skin tones."},{"q":"Is it travel-safe?","a":"Yes \u2014 the slim compact fits easily in a purse for daily touch-ups."}],"usage_tips":"Use the highlighter sparingly \u2014 pearl finishes can build up quickly. Apply blush before highlighter so the shimmer sits cleanly on top. Store away from heat to protect the powder.","social_proof":""},{"id":"84a8663e-c9c9-46a8-8b59-f78ffe612c4d","how_to_use":"Swipe the stick directly onto cheeks (and lips, if you like) and blend with fingertips for a fresh juicy flush.","ingredients":"Caprylic/Capric Triglyceride, Hydrogenated Polyisobutene, Ozokerite, Synthetic Beeswax, Tocopheryl Acetate, Glycerin, Phenoxyethanol. May contain (+/-): Iron Oxides, Carmine, Titanium Dioxide, Mica.","key_benefits":[{"icon":"\ud83c\udf38","text":"Fresh juicy berry shade"},{"icon":"\ud83d\udca7","text":"Creamy hydrating finish"},{"icon":"\u2728","text":"Lips and cheeks 2-in-1"},{"icon":"\ud83e\uddf4","text":"Mess-free twist-up stick"}],"faq":[{"q":"Is it suitable for dry skin?","a":"Yes, the creamy stick formula adds hydration and a soft glow without flaking."},{"q":"Will the colour last all day?","a":"Set lightly with powder over the blush for longer wear on oily areas."},{"q":"Can it be layered with powder blush?","a":"Yes \u2014 use as a base and top with a powder blush for staying power."}],"usage_tips":"Warm a small amount on your fingertips first to control placement. Apply before powder. Cap the stick tightly so it doesn''t dry out at the tip.","social_proof":""},{"id":"4d71bd03-4f13-43ca-9547-3f29f0d608c3","how_to_use":"Swipe directly onto cheeks and lips, then tap and blend with fingertips for a bold rosy flush.","ingredients":"Caprylic/Capric Triglyceride, Hydrogenated Polyisobutene, Ozokerite, Synthetic Beeswax, Tocopheryl Acetate, Glycerin, Phenoxyethanol. May contain (+/-): Iron Oxides, Carmine, Titanium Dioxide.","key_benefits":[{"icon":"\ud83c\udf38","text":"Bold rosy-red shade"},{"icon":"\ud83d\udca7","text":"Creamy hydrating texture"},{"icon":"\u2728","text":"Multi-use cheek and lip"},{"icon":"\ud83e\uddf4","text":"Twist-up convenience"}],"faq":[{"q":"Will Ruby suit warm Pakistani skin?","a":"Yes \u2014 Ruby is a rich rose-red that flatters warm and neutral undertones beautifully."},{"q":"Is it long-lasting on lips?","a":"It gives a stained-lip look; expect natural fading after eating or drinking."},{"q":"Can I apply with a brush?","a":"Yes, dab a stippling brush on the stick and brush onto cheeks for a softer wash."}],"usage_tips":"Use a clean finger or brush to blend the edges out smoothly. Apply on bare skin before foundation for a stained look. Store at room temperature to prevent melting.","social_proof":""},{"id":"68dd8938-2849-48be-8170-6544db783863","how_to_use":"Pick a shade, swipe directly onto cheeks and lips, then blend with fingertips. Layer multiple sticks together to create custom shades.","ingredients":"Caprylic/Capric Triglyceride, Hydrogenated Polyisobutene, Ozokerite, Synthetic Beeswax, Tocopheryl Acetate, Glycerin, Phenoxyethanol. May contain (+/-): Iron Oxides, Carmine, Mica, Titanium Dioxide. Refer to each stick for exact ingredients.","key_benefits":[{"icon":"\ud83c\udf38","text":"Multiple wearable shades"},{"icon":"\ud83d\udca7","text":"Creamy hydrating formulas"},{"icon":"\u2728","text":"Lip and cheek versatility"},{"icon":"\ud83e\uddf4","text":"Budget-friendly bundle"}],"faq":[{"q":"Which shades are included?","a":"Bundle contents may vary \u2014 check the listing image, or contact us for the exact shades available."},{"q":"Are they suitable for sensitive skin?","a":"Pixi blush sticks are generally well tolerated, but always patch test if your skin is reactive."},{"q":"Can I gift the bundle?","a":"Absolutely \u2014 the multi-shade bundle is great for gifting friends or family."}],"usage_tips":"Layer two shades for a custom flush. Use one shade on lips and another on cheeks to switch up your look. Keep each stick capped tightly to preserve the creamy formula.","social_proof":""},{"id":"482ae52e-22c2-48da-8285-474fc8d4ea97","how_to_use":"Apply directly to the apples of cheeks (and lips, if you like) and blend with fingertips. Build colour gradually.","ingredients":"Caprylic/Capric Triglyceride, Hydrogenated Polyisobutene, Ozokerite, Synthetic Beeswax, Tocopheryl Acetate, Glycerin, Phenoxyethanol. May contain (+/-): Iron Oxides, Carmine, Mica.","key_benefits":[{"icon":"\ud83c\udf38","text":"Buy 1 get 1 free deal"},{"icon":"\ud83d\udca7","text":"Creamy hydrating formula"},{"icon":"\u2728","text":"Multi-use lip and cheek"},{"icon":"\ud83e\uddf4","text":"Twist-up no-mess applicator"}],"faq":[{"q":"Can I choose the two shades?","a":"Yes \u2014 shade selection depends on stock. Message us to confirm which shades you''d like."},{"q":"Are both sticks the same size?","a":"Yes, both are full-size Pixi blush sticks."},{"q":"How long does each stick last?","a":"With daily use, each stick typically lasts 3\u20134 months."}],"usage_tips":"Pair contrasting shades for soft daytime and bold nightime looks. Apply on bare skin for a sheer stain. Cap tightly to avoid the cream drying out.","social_proof":""},{"id":"312337f4-0d1c-4a6a-b591-04a93ba6e9c7","how_to_use":"After cleansing, soak a cotton pad and sweep over face and neck. Avoid the eye area. Use up to twice daily \u2014 start with once a day if your skin is new to acids.","ingredients":"Aqua/Water, Glycolic Acid, Aloe Barbadensis Leaf Juice, Hamamelis Virginiana (Witch Hazel) Water, Butylene Glycol, Glycerin, Ammonium Glycolate, Panax Ginseng Root Extract, Aesculus Hippocastanum (Horse Chestnut) Seed Extract, Fructose, Urea, Citric Acid, Sodium PCA, Sodium Hyaluronate, Hexylene Glycol, Biotin, Polysorbate 20, Phenoxyethanol, Caprylyl Glycol, Disodium EDTA, Parfum.","key_benefits":[{"icon":"\u2728","text":"5% glycolic acid exfoliates gently"},{"icon":"\ud83c\udf3f","text":"Aloe + ginseng calm skin"},{"icon":"\ud83d\udca7","text":"Brightens dull, uneven skin"},{"icon":"\ud83c\udf19","text":"Cult-favourite night toner"}],"faq":[{"q":"Can I use it daily?","a":"Start 2\u20133 times a week and build up to daily use as your skin tolerates."},{"q":"Will it dry out my skin?","a":"It''s formulated with hydrating extracts, but always follow with moisturiser and daily SPF."},{"q":"Can pregnant women use it?","a":"Glycolic acid is generally considered safer than retinoids, but consult your doctor first."}],"usage_tips":"Always apply daily sunscreen \u2014 glycolic acid increases sun sensitivity. Avoid layering with strong actives like retinol on the same night. Store away from direct light.","social_proof":""},{"id":"db893c11-1c3e-4ce0-a6d1-f0f9045a9099","how_to_use":"Glide directly onto bare lips, or layer over lipstick for extra shine and hydration. Reapply throughout the day as needed.","ingredients":"Ricinus Communis (Castor) Seed Oil, Octyldodecanol, Caprylic/Capric Triglyceride, Tocopheryl Acetate, Aloe Barbadensis Leaf Extract, Beeswax, Camellia Sinensis Leaf Extract, Mica, Aroma. May contain (+/-): Iron Oxides, Carmine, Titanium Dioxide.","key_benefits":[{"icon":"\ud83d\udca7","text":"Hydrating tinted lip balm"},{"icon":"\ud83c\udf38","text":"Sheer wash of colour"},{"icon":"\u2728","text":"Soft glossy finish"},{"icon":"\ud83e\uddf4","text":"Pocket-friendly tube"}],"faq":[{"q":"Is it sticky?","a":"Not at all \u2014 Pixi LipGlow is a balm-gloss hybrid that feels light and comfortable."},{"q":"Will the tint show on pigmented lips?","a":"It gives a sheer tint that enhances your natural lip colour rather than covering it."},{"q":"Can men use it as a lip balm?","a":"Yes \u2014 the sheer shades are subtle and work well for anyone needing lip hydration."}],"usage_tips":"Use it under matte lipstick as a hydrating base, or over for a juicy finish. Carry it for touch-ups throughout the day. Keep the cap tight to prevent the balm drying out.","social_proof":""},{"id":"6023fca5-f8cf-4d67-903f-3c12c8a77f5f","how_to_use":"Twist up the stick and apply directly to cheeks (and lips). Blend with fingers for a fresh dewy flush of colour.","ingredients":"Caprylic/Capric Triglyceride, Hydrogenated Polyisobutene, Ozokerite, Synthetic Beeswax, Tocopheryl Acetate, Glycerin, Phenoxyethanol. May contain (+/-): Iron Oxides, Carmine, Mica, Titanium Dioxide.","key_benefits":[{"icon":"\ud83c\udf38","text":"Dewy fresh flush of colour"},{"icon":"\ud83d\udca7","text":"Hydrating creamy formula"},{"icon":"\u2728","text":"Lip and cheek multi-tasker"},{"icon":"\ud83e\uddf4","text":"Twist-up no-mess stick"}],"faq":[{"q":"Will it crease over makeup?","a":"Apply on top of foundation before powder and set lightly \u2014 it shouldn''t crease."},{"q":"Is it suitable for oily skin?","a":"Yes, just set with a light powder for extended wear on oily areas."},{"q":"Is the colour buildable?","a":"Very \u2014 start with a small dot and layer for a bolder effect."}],"usage_tips":"Warm a dab on your fingertips to control intensity. Apply before powder for the smoothest blend. Store the stick at room temperature to keep it firm.","social_proof":""},{"id":"38c040ec-21d9-45af-b89c-79f2d292d9e5","how_to_use":"Glide the stick along the cheekbones, hairline, jaw and bridge of nose. Blend with a brush, sponge or fingertips for a soft sun-kissed contour.","ingredients":"Caprylic/Capric Triglyceride, Hydrogenated Polyisobutene, Ozokerite, Synthetic Beeswax, Tocopheryl Acetate, Glycerin, Phenoxyethanol. May contain (+/-): Iron Oxides, Titanium Dioxide, Mica.","key_benefits":[{"icon":"\u2600\ufe0f","text":"Sun-kissed bronze warmth"},{"icon":"\u2728","text":"Creamy blendable stick formula"},{"icon":"\ud83c\udf38","text":"Natural soft-focus finish"},{"icon":"\ud83e\uddf4","text":"Easy to apply on the go"}],"faq":[{"q":"Will the bronzer look muddy?","a":"No, it blends out softly and looks like real warmth on the skin, not muddy or orange."},{"q":"Is it suitable for cool undertones?","a":"The shade leans warm-neutral and works on most undertones; sample before committing if very cool."},{"q":"Can it be used for contouring?","a":"Yes \u2014 perfect for soft contour on the cheek hollows and jawline."}],"usage_tips":"Apply in small dots and blend immediately for the smoothest look. Use with a fluffy brush for diffused finish. Cap tightly after each use.","social_proof":""},{"id":"3a2d99fd-73ab-4566-be03-30f38b52152a","how_to_use":"Swipe directly onto cheeks (and lips) and blend with fingertips for a soft floral flush.","ingredients":"Caprylic/Capric Triglyceride, Hydrogenated Polyisobutene, Ozokerite, Synthetic Beeswax, Tocopheryl Acetate, Glycerin, Phenoxyethanol. May contain (+/-): Iron Oxides, Carmine, Mica.","key_benefits":[{"icon":"\ud83c\udf38","text":"Soft floral pink flush"},{"icon":"\ud83d\udca7","text":"Creamy hydrating finish"},{"icon":"\u2728","text":"Lip and cheek 2-in-1"},{"icon":"\ud83e\uddf4","text":"Twist-up convenience"}],"faq":[{"q":"Will Fleur work on deeper skin?","a":"Fleur is a soft pink with subtle warmth \u2014 it shows well on fair to wheatish; medium-deep skin may prefer a bolder shade."},{"q":"Is it long-lasting?","a":"Set lightly with powder for extended wear, especially on oily areas."},{"q":"Can I use it daily?","a":"Yes, the gentle formula is suitable for daily wear."}],"usage_tips":"Layer two strokes for a more saturated look. Apply on bare skin for a stained-cheek effect. Keep capped at room temperature.","social_proof":""},{"id":"a40af817-e8de-48a8-b809-c25d6d7cee37","how_to_use":"Shake well, then dot a tiny amount onto each cheek and blend immediately with a sponge or fingers. Build slowly \u2014 Rare Beauty blush is very pigmented.","ingredients":"Aqua/Water, Glycerin, Dimethicone, Caprylic/Capric Triglyceride, Lotus Flower Extract, Gardenia Flower Extract, Crocus Flower Extract, Tocopheryl Acetate, Phenoxyethanol. May contain (+/-): Iron Oxides, Carmine, Titanium Dioxide.","key_benefits":[{"icon":"\ud83c\udf38","text":"Soft warm coral ''Hope'' shade"},{"icon":"\ud83d\udca7","text":"Lightweight liquid texture"},{"icon":"\u2728","text":"Highly pigmented buildable"},{"icon":"\ud83e\uddf4","text":"Long-wearing fresh finish"}],"faq":[{"q":"Is one drop really enough?","a":"Yes \u2014 Rare Beauty blush is extremely pigmented. One small dot per cheek is plenty."},{"q":"Will Hope suit warm Pakistani skin?","a":"Hope is a soft warm coral that flatters wheatish to medium skin beautifully."},{"q":"Is it dewy or matte?","a":"It dries to a soft semi-matte finish that still looks fresh, not flat."}],"usage_tips":"Blend within seconds \u2014 the formula sets fast and grips skin. Apply over moisturised skin for the smoothest blend. Always shake the bottle before each use.","social_proof":""},{"id":"ade38094-2ee1-40dc-b574-53b8775ce9a3","how_to_use":"Use each brush and sponge for its designed purpose: foundation brush for liquid foundation, powder brush for setting, blush brush for cheeks, and damp sponge for blending.","ingredients":"Brushes: Synthetic Taklon bristles, aluminium ferrule, plastic handle. Sponge: Hydrophilic polyurethane foam.","key_benefits":[{"icon":"\ud83e\uddf4","text":"Complete starter brush set"},{"icon":"\u2728","text":"Cruelty-free synthetic bristles"},{"icon":"\ud83d\udca7","text":"Soft, non-shedding feel"},{"icon":"\ud83d\udee1\ufe0f","text":"Trusted Real Techniques quality"}],"faq":[{"q":"How often should I wash the brushes?","a":"Wash brushes and sponge weekly with a gentle shampoo or brush cleanser to prevent breakouts."},{"q":"Are they suitable for sensitive skin?","a":"Yes \u2014 the soft synthetic bristles are gentle and hypoallergenic."},{"q":"Is the sponge latex-free?","a":"Yes, the Real Techniques sponge is latex-free and safe for sensitive skin."}],"usage_tips":"Dampen the sponge before each use \u2014 it bounces back to almost double its size for the smoothest blend. Let brushes air-dry bristles-down to preserve shape. Replace the sponge every 1\u20133 months.","social_proof":""},{"id":"9707b423-2884-4d7a-9de3-bed550b8748a","how_to_use":"Use the foundation brush to apply liquid base, the contour brush for sculpting, the blush brush for cheeks and the setting brush for powder. Clean weekly.","ingredients":"Synthetic Taklon bristles, aluminium ferrule, plastic handle. Vegan and cruelty-free.","key_benefits":[{"icon":"\ud83e\uddf4","text":"Face base essentials in one set"},{"icon":"\u2728","text":"Synthetic vegan bristles"},{"icon":"\ud83d\udca7","text":"Soft, skin-friendly feel"},{"icon":"\ud83d\udee1\ufe0f","text":"Cruelty-free certified"}],"faq":[{"q":"Is the set good for beginners?","a":"Yes \u2014 it covers the four essential face brushes, perfect for someone building a kit."},{"q":"Will the bristles shed?","a":"Real Techniques brushes are designed to be durable and minimal-shedding when properly cared for."},{"q":"How do I clean them?","a":"Use a gentle brush cleanser or baby shampoo, rinse and air-dry flat or bristles-down."}],"usage_tips":"Use the foundation brush with stippling motions instead of dragging for the smoothest finish. Keep the brushes in a holder bristles-up after they dry. Don''t soak the ferrule \u2014 it can loosen the glue.","social_proof":""},{"id":"e00f1e17-4673-4370-b862-5324b26d37b6","how_to_use":"Squeeze a small amount onto the wand and glide over lips. Reapply throughout the day for hydration and a hint of colour.","ingredients":"Ricinus Communis (Castor) Seed Oil, Octyldodecanol, Hydrogenated Polyisobutene, Tocopheryl Acetate, Peptides, Shea Butter, Aroma. May contain (+/-): Iron Oxides, Carmine, Mica.","key_benefits":[{"icon":"\ud83c\udf38","text":"Sheer raspberry-jelly tint"},{"icon":"\ud83d\udca7","text":"Peptides + shea hydrate"},{"icon":"\u2728","text":"High-shine non-sticky finish"},{"icon":"\ud83e\uddf4","text":"Cult Rhode formula"}],"faq":[{"q":"Is it sticky?","a":"No, the formula feels cushiony and smooth, not tacky like traditional glosses."},{"q":"Will the tint show on pigmented lips?","a":"It gives a soft raspberry wash \u2014 buildable but still sheer. Layer for more intensity."},{"q":"Is the product authentic?","a":"Yes, sourced directly through verified channels with original packaging."}],"usage_tips":"Layer over a lip liner for a fuller defined pout. Carry it in your bag for hydrating touch-ups. Keep cap tight to prevent the gel drying out.","social_proof":""},{"id":"208fc198-5a41-4155-9ba7-74e28021c7fb","how_to_use":"Apply directly to lips with the doe-foot wand. Reapply throughout the day for hydration and colour.","ingredients":"Ricinus Communis (Castor) Seed Oil, Octyldodecanol, Hydrogenated Polyisobutene, Tocopheryl Acetate, Peptides, Shea Butter, Aroma. May contain (+/-): Iron Oxides, Carmine, Mica.","key_benefits":[{"icon":"\ud83d\udca7","text":"Peptide-infused hydrating tint"},{"icon":"\ud83c\udf38","text":"Range of wearable shades"},{"icon":"\u2728","text":"Glossy non-sticky finish"},{"icon":"\ud83e\uddf4","text":"Iconic Rhode formula"}],"faq":[{"q":"Which shade should I pick?","a":"It depends on your preference \u2014 Raspberry Jelly, Toast, Espresso and Strawberry Glaze are all popular. Message us to discuss."},{"q":"Are these original Rhode tints?","a":"Yes, we stock authentic Rhode Peptide Lip Tints with original packaging."},{"q":"Is it good for dry lips?","a":"Yes \u2014 peptides and shea butter make it deeply hydrating, even on chapped lips."}],"usage_tips":"Layer over lip balm in winter for extra comfort. Use over a lip liner for definition. Keep the cap tightly closed and away from heat.","social_proof":""},{"id":"300f0b05-796d-40b5-912a-adfcddb0471e","how_to_use":"Swirl a fluffy brush across the powder and tap onto the apples of the cheeks. Build colour gradually for a soft to bold flush.","ingredients":"Talc, Mica, Magnesium Stearate, Caprylic/Capric Triglyceride, Tocopheryl Acetate, Phenoxyethanol. May contain (+/-): Iron Oxides, Carmine, Titanium Dioxide.","key_benefits":[{"icon":"\ud83c\udf38","text":"Pigmented warm-pink flush"},{"icon":"\u2728","text":"Buttery blendable powder"},{"icon":"\ud83d\udc9b","text":"Long-wearing finish"},{"icon":"\ud83e\uddf4","text":"Affordable cult-favourite"}],"faq":[{"q":"Is Risky Business too dark for fair skin?","a":"It is pigmented \u2014 use a light hand on fair skin and tap off excess from the brush."},{"q":"Will it last all day?","a":"Yes, especially when applied over a cream blush base and set with setting spray."},{"q":"Does it have shimmer?","a":"It has a soft satin finish, not chunky shimmer."}],"usage_tips":"Tap excess powder off the brush before applying. Use a fluffy brush for a diffused look. Keep the compact closed to prevent powder breakage.","social_proof":""},{"id":"999a6fae-e382-40df-aac7-6b0b0c2ff7b5","how_to_use":"Apply a thin layer to clean lips. You''ll feel a tingling sensation as it plumps. Reapply as needed for fuller-looking lips.","ingredients":"Polybutene, Hydrogenated Polyisobutene, Octyldodecanol, Mentha Piperita (Peppermint) Oil, Capsicum Frutescens Fruit Extract, Tocopheryl Acetate, Hyaluronic Acid, Aroma.","key_benefits":[{"icon":"\ud83d\udca7","text":"Plumps with hyaluronic acid"},{"icon":"\u2728","text":"Glossy high-shine finish"},{"icon":"\ud83c\udf38","text":"Subtle pink tint"},{"icon":"\ud83e\uddf4","text":"Affordable plumping gloss"}],"faq":[{"q":"Is the tingling sensation safe?","a":"Yes \u2014 the gentle tingle is from natural cinnamon/peppermint extracts. If it feels uncomfortable, wipe off and discontinue."},{"q":"Will it work on thin lips?","a":"Yes, with consistent use you''ll see a fuller, more hydrated lip look."},{"q":"Can I wear it over lipstick?","a":"Yes \u2014 apply over lipstick for an extra plump glossy finish."}],"usage_tips":"Patch test on the inner wrist if you have sensitive skin. Avoid layering with other strong actives on lips. Keep tightly closed at room temperature.","social_proof":""},{"id":"8ff15463-3a19-47d3-84e8-fd13d65057f4","how_to_use":"Shake well, dot a small amount onto cheeks and blend immediately with fingers, a sponge or brush. Build colour gradually for a soft to bold flush.","ingredients":"Aqua/Water, Glycerin, Dimethicone, Caprylic/Capric Triglyceride, Tocopheryl Acetate, Phenoxyethanol. May contain (+/-): Iron Oxides, Carmine, Titanium Dioxide.","key_benefits":[{"icon":"\ud83c\udf38","text":"Multiple wearable shades"},{"icon":"\ud83d\udca7","text":"Dewy buildable finish"},{"icon":"\u2728","text":"Highly pigmented liquid"},{"icon":"\ud83e\uddf4","text":"Budget-friendly drugstore favourite"}],"faq":[{"q":"Which shade is best for my skin tone?","a":"Warm tones suit terracotta or peach; cool tones suit rose or mauve. Message us for a personalised recommendation."},{"q":"Is it long-lasting?","a":"Yes \u2014 set lightly with powder for extended wear, up to 8 hours."},{"q":"Will a little bit go a long way?","a":"Yes, the formula is very pigmented. Start with a single dot per cheek."}],"usage_tips":"Blend within seconds \u2014 the formula sets fast. Apply over foundation, before powder. Always shake the bottle to mix the pigments evenly.","social_proof":""},{"id":"ed4f1b94-d9cd-472e-ae2d-58c010c48654","how_to_use":"Use the doe-foot to apply under eyes, around the nose, and on blemishes. Blend with a damp sponge or fingertip. Build for full coverage.","ingredients":"Aqua/Water, Cyclopentasiloxane, Mica, Glycerin, Dimethicone, Squalane, Hyaluronic Acid, Tocopheryl Acetate, Phenoxyethanol. May contain (+/-): Iron Oxides, Titanium Dioxide.","key_benefits":[{"icon":"\u2728","text":"Full-coverage crease-free finish"},{"icon":"\ud83d\udca7","text":"Hyaluronic acid + squalane hydrate"},{"icon":"\ud83c\udf38","text":"Brightens under-eye area"},{"icon":"\ud83e\uddf4","text":"Iconic Tarte Shape Tape"}],"faq":[{"q":"Which shade should I pick for medium Pakistani skin?","a":"Shades like Light-Medium Honey, Tan-Sand, Medium Sand work well for wheatish skin. Match it to one shade lighter than your foundation under the eyes."},{"q":"Will it crease under the eyes?","a":"The creamy formula is designed to flex with skin and set without creasing \u2014 set lightly with powder."},{"q":"Is it good for dry under-eyes?","a":"Yes, the hydrating ingredients keep it from settling into fine lines."}],"usage_tips":"Use a damp sponge to press in rather than wipe. Set with a light translucent powder to lock the concealer in place. Don''t apply too thickly \u2014 a little goes a long way.","social_proof":""},{"id":"6f6d550b-3d53-47a6-94be-efa34c034ce0","how_to_use":"Soak a cotton pad and sweep over face and neck after cleansing in the evening. Avoid the eye area. Start with 2\u20133 nights a week and build up.","ingredients":"Aqua (Water), Glycolic Acid, Rosa Damascena Flower Water, Centaurea Cyanus Flower Water, Aloe Barbadensis Leaf Water, Propanediol, Glycerin, Triethanolamine, Aminomethyl Propanol, Panthenol, Sodium Hyaluronate Crosspolymer, Tasmannia Lanceolata Fruit/Leaf Extract, Aspartic Acid, Alanine, Glycine, Serine, Valine, Isoleucine, Proline, Threonine, Histidine, Phenylalanine, Glutamic Acid, Arginine, PCA, Sodium PCA, Sodium Lactate, Fructose, Glucose, Sucrose, Urea, Hexyl Nicotinate, Dextrin, Citric Acid, Polysorbate 20, Gellan Gum, Trisodium Ethylenediamine Disuccinate, Sodium Chloride, Hexylene Glycol, Potassium Sorbate, Sodium Benzoate, Pentylene Glycol, 1,2-Hexanediol, Caprylyl Glycol.","key_benefits":[{"icon":"\u2728","text":"7% glycolic acid exfoliates"},{"icon":"\ud83c\udf3f","text":"Rose + aloe soothe skin"},{"icon":"\ud83d\udca7","text":"Smooths texture and tone"},{"icon":"\ud83c\udf19","text":"Best as a night treatment"}],"faq":[{"q":"How is it different from Pixi Glow Tonic?","a":"The Ordinary''s toner has a higher 7% glycolic acid concentration vs Pixi''s 5% \u2014 stronger exfoliation, recommended for experienced users."},{"q":"Will it irritate sensitive skin?","a":"Start with 1\u20132 nights a week and patch test first; discontinue if redness persists."},{"q":"Should I wear SPF?","a":"Yes \u2014 daily SPF is essential when using glycolic acid as it increases sun sensitivity."}],"usage_tips":"Use at night, not in the morning. Don''t layer with retinol or other strong acids on the same night. Store in a cool dry place away from sunlight.","social_proof":""},{"id":"1ae7ea16-ad55-4d90-ac0b-a59fb3102b8e","how_to_use":"Apply a thin layer to clean, dry affected areas at night before bed. Avoid the eye area. Always follow with sunscreen the next morning.","ingredients":"Kojic Acid, Glutathione, Hydroquinone-free brightening complex, Glycerin, Vitamin E, Hyaluronic Acid, Niacinamide, Phenoxyethanol. Multi-ingredient formulation; check the package leaflet for the complete list.","key_benefits":[{"icon":"\u2728","text":"Targets melasma and dark patches"},{"icon":"\ud83c\udf3f","text":"Kojic acid + glutathione brighten"},{"icon":"\ud83d\udca7","text":"Niacinamide evens skin tone"},{"icon":"\ud83c\udf19","text":"Best used as night cream"}],"faq":[{"q":"How long until I see results?","a":"Most users notice a brightening effect within 4\u20138 weeks of consistent night-time use."},{"q":"Is it safe during pregnancy?","a":"Avoid use during pregnancy and breastfeeding \u2014 consult your dermatologist first."},{"q":"Can I use it during the day?","a":"Best used at night. Always pair with broad-spectrum SPF during the day."}],"usage_tips":"Patch test on the inner arm for 48 hours before full-face use. Do not use with strong acids or retinol on the same night. SPF every morning is non-negotiable \u2014 without it, you''ll undo your progress.","social_proof":""},{"id":"d5cbefcb-34d3-4b59-819c-8e842686dd67","how_to_use":"Dampen a sponge and pick up the base, then press onto the face for full coverage. Or apply with fingers for a sheer wash. Set with powder.","ingredients":"Aqua/Water, Glycerin, Talc, Mica, Caprylic/Capric Triglyceride, Iron Oxides, Titanium Dioxide, Phenoxyethanol, Dimethicone. Refer to packaging for full list.","key_benefits":[{"icon":"\ud83c\udf38","text":"Full-coverage water-activated base"},{"icon":"\u2728","text":"Buildable from sheer to opaque"},{"icon":"\ud83d\udca7","text":"Works for stage and special FX"},{"icon":"\ud83e\uddf4","text":"Long-wearing formula"}],"faq":[{"q":"Can I use it as everyday foundation?","a":"AquaColor is best for special events, performances or photo shoots \u2014 it''s heavier than daily wear foundation."},{"q":"Does it transfer onto clothes?","a":"Once set with powder it transfers minimally \u2014 but avoid heavy rubbing."},{"q":"How do I remove it?","a":"Use an oil cleanser followed by a gentle face wash to fully remove."}],"usage_tips":"Always seal with a translucent powder and setting spray for long wear. Use minimal water for full coverage; more water for a sheer wash. Store in a cool dry place.","social_proof":""},{"id":"cef3c37b-7119-4f71-b952-50fcf7580112","how_to_use":"After shampooing, apply generously to wet hair from mid-lengths to ends. Leave on 5\u201310 minutes, then rinse thoroughly. Use 1\u20132 times a week.","ingredients":"Aqua/Water, Cetearyl Alcohol, Behentrimonium Methosulfate, Argania Spinosa (Argan) Kernel Oil, Glycerin, Hydrolyzed Keratin, Panthenol, Tocopheryl Acetate, Cyclopentasiloxane, Dimethicone, Parfum, Phenoxyethanol, Citric Acid.","key_benefits":[{"icon":"\ud83d\udca7","text":"Argan oil deeply nourishes"},{"icon":"\ud83c\udf3f","text":"Keratin strengthens strands"},{"icon":"\u2728","text":"Adds shine and smoothness"},{"icon":"\ud83e\uddf4","text":"Reduces frizz and breakage"}],"faq":[{"q":"Is it suitable for oily scalp?","a":"Yes, just apply from mid-lengths to ends and avoid the scalp."},{"q":"How often should I use it?","a":"1\u20132 times a week is ideal \u2014 overuse can weigh the hair down."},{"q":"Will it work on coloured hair?","a":"Yes, the argan-keratin formula is gentle and safe for coloured and chemically-treated hair."}],"usage_tips":"Comb through with a wide-tooth comb for even distribution. For deeper conditioning, cover with a shower cap and warm towel before rinsing. Rinse with cool water to seal the cuticle for extra shine.","social_proof":""},{"id":"f376311d-532b-44d1-8c98-95b1285488cc","how_to_use":"Take one tablet or capsule daily with food, or as directed by your physician.","ingredients":"Multi-ingredient formulation; consult the package leaflet for the complete ingredient list and adult dosing instructions.","key_benefits":[{"icon":"\ud83d\udcaa","text":"Joint and bone support"},{"icon":"\ud83c\udf3f","text":"Anti-inflammatory blend"},{"icon":"\u26a1","text":"Supports mobility"},{"icon":"\ud83d\udee1\ufe0f","text":"Daily wellness aid"}],"faq":[{"q":"When should I take it?","a":"Most users take it with breakfast or lunch \u2014 follow your doctor''s instructions."},{"q":"Are there side effects?","a":"Generally well tolerated. Stop and consult a doctor if you notice any reaction."},{"q":"Can pregnant women use it?","a":"Always consult your physician before using any supplement during pregnancy."}],"usage_tips":"Take consistently for 4\u20138 weeks to see steady benefits. Store in a cool dry place away from sunlight. Pair with balanced nutrition and gentle movement.","social_proof":""},{"id":"97520dc1-edb6-42e6-9cf9-3b681b45a0d7","how_to_use":"Take one tablet daily with a glass of water, preferably with a meal, or as advised by your healthcare provider.","ingredients":"Ascorbic Acid (Vitamin C), Bioflavonoids, Zinc. Multi-ingredient formulation; consult the package leaflet for the complete ingredient list and adult dosing instructions.","key_benefits":[{"icon":"\ud83d\udee1\ufe0f","text":"Supports immunity"},{"icon":"\u2728","text":"Brightens skin from within"},{"icon":"\ud83c\udf3f","text":"Antioxidant protection"},{"icon":"\ud83d\udcaa","text":"Supports women''s daily wellness"}],"faq":[{"q":"Is it safe during pregnancy?","a":"Vitamin C is generally safe, but please consult your physician before adding any supplement during pregnancy."},{"q":"Can I take it with other vitamins?","a":"Yes, Vitamin C pairs well with iron supplements (it boosts absorption). Discuss combinations with your doctor."},{"q":"When is the best time to take it?","a":"Take with food in the morning for the steadiest absorption."}],"usage_tips":"Avoid taking on an empty stomach if you have a sensitive digestive system. Store in a cool dry place. Take daily for at least 6\u20138 weeks for visible skin and immunity benefits.","social_proof":""},{"id":"d8711d3f-4013-4a38-8206-ae32de49ded5","how_to_use":"Use each product in the combo as directed on its packaging. Typically, give one age-appropriate dose daily after meals, or as recommended by your paediatrician.","ingredients":"Bundle contains multiple pediatric supplements. Multi-ingredient formulation; consult the package leaflet for the complete ingredient list and dosing instructions.","key_benefits":[{"icon":"\ud83d\udc9b","text":"Complete pediatric nutrition support"},{"icon":"\ud83d\udcaa","text":"Supports growth and development"},{"icon":"\ud83c\udf3f","text":"Vitamins and minerals for kids"},{"icon":"\ud83d\udee1\ufe0f","text":"Bundled at a saving"}],"faq":[{"q":"What age is this combo for?","a":"Each item has its own age recommendation \u2014 check the individual packaging or consult your paediatrician."},{"q":"Are these supplements safe for daily use?","a":"Yes when given at the recommended dose. Always follow the paediatrician''s advice."},{"q":"What if my child refuses one of the items?","a":"Many can be mixed with milk or food. Speak to your doctor if your child struggles."}],"usage_tips":"Keep all bottles tightly closed and out of reach of children. Maintain a regular schedule \u2014 consistency matters most for paediatric nutrition. Store in a cool dry place.","social_proof":""},{"id":"86daa48d-1062-4a13-a725-9e61d4097a7c","how_to_use":"Swirl the brush over powder or cream blush, tap off excess, then sweep onto the apples of the cheeks and blend up toward the temple.","ingredients":"Synthetic Taklon bristles, aluminium ferrule, plastic handle. Vegan and cruelty-free.","key_benefits":[{"icon":"\ud83e\uddf4","text":"Soft tapered blush brush"},{"icon":"\u2728","text":"Picks up the right amount of product"},{"icon":"\ud83d\udca7","text":"Minimal shedding bristles"},{"icon":"\ud83d\udee1\ufe0f","text":"Real Techniques cruelty-free quality"}],"faq":[{"q":"Does it work with cream blush too?","a":"Yes, the synthetic bristles handle both powder and cream products beautifully."},{"q":"How often should I clean it?","a":"Wash with brush cleanser or gentle shampoo at least once a week."},{"q":"Will the bristles shed?","a":"Real Techniques brushes are designed to be durable with minimal shedding."}],"usage_tips":"Tap off excess powder before applying to avoid muddy blush. Let air-dry bristles-down to maintain shape. Don''t soak the ferrule \u2014 it can loosen the glue.","social_proof":""},{"id":"542902e2-4ac5-4b8d-8a00-4b3ada84698a","how_to_use":"Take one tablet daily with a glass of water, preferably after a meal, or as directed by your physician.","ingredients":"Calcium Carbonate, Vitamin D3, Magnesium, Zinc. Multi-ingredient formulation; consult the package leaflet for the complete ingredient list and adult dosing instructions.","key_benefits":[{"icon":"\ud83d\udcaa","text":"Supports bone density"},{"icon":"\ud83c\udf3f","text":"Calcium + Vitamin D for women"},{"icon":"\ud83d\udee1\ufe0f","text":"Helps prevent deficiency"},{"icon":"\u2728","text":"Daily wellness aid"}],"faq":[{"q":"Is it safe during pregnancy?","a":"Calcium and Vitamin D are commonly prescribed in pregnancy \u2014 confirm dosage with your doctor."},{"q":"Can I take it with other supplements?","a":"Yes, but space it from iron supplements as calcium can reduce iron absorption."},{"q":"Any side effects?","a":"Mild constipation may occur \u2014 increase water and fibre intake. Stop if symptoms persist."}],"usage_tips":"Take after meals for better absorption and to reduce stomach upset. Stay hydrated throughout the day. Maintain consistent daily use for 3+ months for visible bone-health benefits.","social_proof":""},{"id":"138ac003-2125-4b45-9804-3c6dea8d01fe","how_to_use":"Take one tablet daily with water after a meal, or as directed by your healthcare provider.","ingredients":"Calcium Citrate, Vitamin D3, Magnesium, Zinc, Vitamin K2. Multi-ingredient formulation; consult the package leaflet for the complete ingredient list and adult dosing instructions.","key_benefits":[{"icon":"\ud83d\udcaa","text":"Strengthens bones and teeth"},{"icon":"\ud83c\udf3f","text":"Calcium + Vit D + K2 blend"},{"icon":"\ud83d\udee1\ufe0f","text":"Supports joint health"},{"icon":"\u2728","text":"Easy daily tablet"}],"faq":[{"q":"When is the best time to take Calin G?","a":"Most users take it with dinner \u2014 calcium absorbs better with food."},{"q":"Is it suitable for elderly users?","a":"Yes, it is commonly recommended for adults at risk of bone density loss."},{"q":"Any side effects?","a":"Generally well tolerated. Consult your doctor if you have kidney issues."}],"usage_tips":"Don''t take it at the same time as iron or thyroid medication \u2014 separate by at least 2 hours. Stay hydrated. Pair with vitamin-rich food and light weight-bearing exercise.","social_proof":""},{"id":"ba9e0268-3dbb-4bfb-8bee-ac155a5ccdf9","how_to_use":"Take one tablet daily with water, preferably with food, or as advised by your physician.","ingredients":"Multi-ingredient formulation; consult the package leaflet for the complete ingredient list and adult dosing instructions.","key_benefits":[{"icon":"\ud83d\udee1\ufe0f","text":"Supports immune function"},{"icon":"\ud83c\udf3f","text":"Daily wellness blend"},{"icon":"\ud83d\udcaa","text":"Helps body resilience"},{"icon":"\u26a1","text":"Easy-to-take tablet"}],"faq":[{"q":"When should I take it?","a":"Take in the morning with breakfast for best absorption."},{"q":"Is it safe long-term?","a":"Generally yes, but follow your doctor''s advice for prolonged use."},{"q":"Can children take it?","a":"Designed for adults \u2014 paediatric dosing must come from a doctor."}],"usage_tips":"Keep the bottle tightly closed and away from heat. Maintain a consistent daily routine for best results. Pair with a vitamin-rich diet and good sleep.","social_proof":""},{"id":"eebbc10e-a8ae-4f68-bfd2-815cc91a5c79","how_to_use":"Take one tablet or capsule daily with water, after a meal, or as directed by your physician.","ingredients":"Ascorbic Acid (Vitamin C), Citrus Bioflavonoids, Rosehip Extract. Multi-ingredient formulation; consult the package leaflet for the complete ingredient list and adult dosing instructions.","key_benefits":[{"icon":"\ud83d\udee1\ufe0f","text":"Daily immunity support"},{"icon":"\u2728","text":"Vitamin C antioxidant"},{"icon":"\ud83c\udf3f","text":"Supports collagen production"},{"icon":"\ud83d\udcaa","text":"Boosts energy and resilience"}],"faq":[{"q":"Can I take it daily?","a":"Yes, Vitamin C is water-soluble and can be taken daily within the recommended dose."},{"q":"Is it safe in pregnancy?","a":"Vitamin C is generally safe but always confirm dosage with your doctor."},{"q":"Will it help with cold and flu?","a":"Vitamin C supports immune function and may reduce the duration of colds when taken consistently."}],"usage_tips":"Take with food to prevent stomach acidity. Avoid mega-dosing \u2014 stick to the recommended daily amount. Pair with a balanced diet for the best long-term benefit.","social_proof":""},{"id":"4db84890-61a8-45bd-9fa9-b16f6d05bb3d","how_to_use":"Cleanse and tone your face, then pierce one ampoule and apply the contents to face and neck. Massage gently until absorbed. Use morning and/or night.","ingredients":"Aqua/Water, Centella Asiatica Extract, Niacinamide, Glycerin, Sodium Hyaluronate, Panthenol, Tocopheryl Acetate, Allantoin, Phenoxyethanol, 1,2-Hexanediol.","key_benefits":[{"icon":"\ud83c\udf3f","text":"Centella soothes redness"},{"icon":"\u2728","text":"Niacinamide brightens skin"},{"icon":"\ud83d\udca7","text":"Hyaluronic acid hydrates"},{"icon":"\ud83d\udee1\ufe0f","text":"Strengthens skin barrier"}],"faq":[{"q":"Is it safe for sensitive skin?","a":"Yes \u2014 centella asiatica is calming and gentle, but patch test first if your skin is reactive."},{"q":"How many ampoules per use?","a":"One ampoule (~3\u20135ml) covers face and neck. Use once or twice daily."},{"q":"Can I use it with retinol?","a":"Yes \u2014 the soothing centella complex helps offset retinol irritation."}],"usage_tips":"Apply on slightly damp skin to lock in extra moisture. Layer your moisturiser on top. Store in a cool dry place \u2014 refrigeration can extend potency.","social_proof":""},{"id":"c6eca929-e48a-426f-9f4f-e4cb5ec113db","how_to_use":"Take one tablet daily with water, preferably with a meal, or as directed by your physician.","ingredients":"Citicoline, B-Complex Vitamins. Multi-ingredient formulation; consult the package leaflet for the complete ingredient list and adult dosing instructions.","key_benefits":[{"icon":"\ud83e\uddec","text":"Supports cognitive function"},{"icon":"\u26a1","text":"Boosts mental clarity"},{"icon":"\ud83c\udf3f","text":"Aids memory and focus"},{"icon":"\ud83d\udcaa","text":"Daily brain wellness"}],"faq":[{"q":"When should I take it?","a":"Take in the morning with breakfast for best mental clarity benefits during the day."},{"q":"How long until I notice a difference?","a":"Most users report improved focus within 2\u20134 weeks of consistent use."},{"q":"Any side effects?","a":"Generally well tolerated. Stop and consult your doctor if you experience headache or insomnia."}],"usage_tips":"Avoid taking late in the evening as it can affect sleep. Combine with good sleep and hydration for the strongest cognitive benefit. Store in a cool dry place.","social_proof":""},{"id":"29399e5d-fc0a-4687-b7e8-4cffcb97970f","how_to_use":"Each partner takes their respective supplement(s) daily as directed on the individual product packaging, or as advised by your fertility specialist.","ingredients":"Bundle contains multiple fertility supplements for him and her. Multi-ingredient formulation; consult the package leaflet for the complete ingredient list and dosing instructions.","key_benefits":[{"icon":"\ud83d\udc9b","text":"Supports both partners'' fertility"},{"icon":"\ud83c\udf3f","text":"Balanced nutrient blend"},{"icon":"\ud83d\udcaa","text":"Aids reproductive wellness"},{"icon":"\ud83d\udee1\ufe0f","text":"Bundled at a saving"}],"faq":[{"q":"How long should we take it?","a":"Most fertility supplements are taken for at least 3 months \u2014 speak to your fertility specialist for a personalised plan."},{"q":"Are they safe?","a":"When taken as directed, yes. Always consult your doctor, especially if undergoing fertility treatments."},{"q":"When should the woman stop her supplement if she conceives?","a":"Many supplements can continue into prenatal care; consult your OB/GYN for the right transition."}],"usage_tips":"Keep both bottles in one place to remember daily doses. Pair with a balanced diet, sleep and reduced caffeine. Track your progress for 3 months before assessing results.","social_proof":""},{"id":"309f45d8-f764-4c33-b7b4-ec8c67a56e9a","how_to_use":"Take one sachet or tablet daily with water, or as directed by your physician.","ingredients":"Cranberry Extract, Vitamin C, D-Mannose. Multi-ingredient formulation; consult the package leaflet for the complete ingredient list and adult dosing instructions.","key_benefits":[{"icon":"\ud83d\udee1\ufe0f","text":"Supports urinary tract health"},{"icon":"\ud83c\udf3f","text":"Cranberry + D-mannose blend"},{"icon":"\ud83d\udca7","text":"Antioxidant protection"},{"icon":"\ud83d\udcaa","text":"Daily wellness aid"}],"faq":[{"q":"Can I take it if I have a UTI?","a":"It supports urinary tract health but is not a substitute for antibiotic treatment \u2014 see your doctor for an active infection."},{"q":"Is it safe in pregnancy?","a":"Generally considered safe but always confirm with your doctor."},{"q":"How long should I take it?","a":"Many users take it for 1\u20133 months as part of preventive UTI care."}],"usage_tips":"Drink plenty of water throughout the day to support urinary health. Take consistently for the best preventive effect. Store in a cool dry place.","social_proof":""},{"id":"48072c40-fac2-4a21-901b-82ede00ed049","how_to_use":"Take as directed on the packaging or by your physician, typically one dose daily with water.","ingredients":"Multi-ingredient formulation; consult the package leaflet for the complete ingredient list and adult dosing instructions.","key_benefits":[{"icon":"\ud83d\udcaa","text":"Supports digestive comfort"},{"icon":"\ud83c\udf3f","text":"Soothing herbal blend"},{"icon":"\ud83d\udee1\ufe0f","text":"Helps balance gut function"},{"icon":"\u26a1","text":"Daily wellness support"}],"faq":[{"q":"When should I take it?","a":"Usually with or after meals \u2014 follow your doctor''s recommendation."},{"q":"Any side effects?","a":"Generally well tolerated. Stop and consult your doctor if you have unusual symptoms."},{"q":"Is it safe long-term?","a":"Most supplements in this category are safe long-term when used as directed. Confirm with your doctor."}],"usage_tips":"Take consistently and stay hydrated. Pair with a balanced diet rich in fibre. Store in a cool dry place away from sunlight.","social_proof":""},{"id":"d53916a1-e90f-4ed7-8786-22e67f77db99","how_to_use":"Take one tablet or sachet daily with water, preferably in the morning, or as advised by your physician.","ingredients":"B-Complex Vitamins, Coenzyme Q10, L-Carnitine, Ginseng Extract. Multi-ingredient formulation; consult the package leaflet for the complete ingredient list and adult dosing instructions.","key_benefits":[{"icon":"\u26a1","text":"Boosts daily energy"},{"icon":"\ud83d\udcaa","text":"Reduces fatigue"},{"icon":"\ud83c\udf3f","text":"B-complex + CoQ10 blend"},{"icon":"\ud83d\udd25","text":"Supports performance"}],"faq":[{"q":"Will it keep me awake at night?","a":"Best taken in the morning. Some users may feel energised, so avoid taking it after 4pm."},{"q":"Is it safe with caffeine?","a":"Generally yes, but you may need less coffee than usual. Listen to your body."},{"q":"Can pregnant women take it?","a":"Consult your doctor before use in pregnancy or breastfeeding."}],"usage_tips":"Take with breakfast for the smoothest energy. Stay hydrated through the day. Pair with consistent sleep and a balanced diet for the best results.","social_proof":""},{"id":"cc30e75b-9802-4c18-a1d7-15e4ba7fef30","how_to_use":"Give the recommended number of drops as per age/weight on the packaging, or as directed by your paediatrician. Use the included dropper for accurate dosing.","ingredients":"Multi-ingredient formulation; consult the package leaflet for the complete ingredient list and dosing instructions.","key_benefits":[{"icon":"\ud83d\udc9b","text":"Easy-dose paediatric drops"},{"icon":"\ud83c\udf3f","text":"Gentle on tiny tummies"},{"icon":"\ud83d\udcaa","text":"Daily wellness support"},{"icon":"\ud83d\udee1\ufe0f","text":"Doctor-formulated blend"}],"faq":[{"q":"Is it safe for newborns?","a":"Always confirm the appropriate age with your paediatrician before use."},{"q":"Any taste?","a":"Most paediatric drops have a mild pleasant taste \u2014 check the leaflet for details."},{"q":"How should I store it?","a":"Keep in a cool dry place away from direct sunlight. Some drops may require refrigeration after opening."}],"usage_tips":"Use the included dropper for precise dosing \u2014 don''t guess. Keep the bottle tightly closed and out of reach of children. Maintain a daily routine for steady benefits.","social_proof":""},{"id":"888c3fce-aa39-4a5e-b249-b4580e4bfd3f","how_to_use":"Take one tablet daily with water, preferably with food, or as directed by your gynaecologist.","ingredients":"Multi-ingredient formulation; consult the package leaflet for the complete ingredient list and adult dosing instructions.","key_benefits":[{"icon":"\ud83d\udc9b","text":"Supports women''s hormonal health"},{"icon":"\ud83c\udf3f","text":"Daily wellness blend"},{"icon":"\ud83d\udcaa","text":"Aids menstrual comfort"},{"icon":"\ud83d\udee1\ufe0f","text":"Doctor-recommended formula"}],"faq":[{"q":"Is it safe during pregnancy?","a":"Consult your gynaecologist before use in pregnancy or while breastfeeding."},{"q":"How long should I take it?","a":"Typical courses are 1\u20133 months, but your doctor''s recommendation always comes first."},{"q":"Any side effects?","a":"Generally well tolerated. Stop and consult your doctor if you experience unusual symptoms."}],"usage_tips":"Take with food to prevent stomach upset. Maintain consistent daily intake. Store in a cool dry place away from sunlight.","social_proof":""},{"id":"3f822cff-41a8-4489-a2c1-274f13235fe0","how_to_use":"Take one tablet daily with water, after a meal, or as directed by your physician.","ingredients":"Iron, Folic Acid, Vitamin B12, Vitamin C. Multi-ingredient formulation; consult the package leaflet for the complete ingredient list and adult dosing instructions.","key_benefits":[{"icon":"\ud83d\udcaa","text":"Supports iron levels"},{"icon":"\ud83c\udf3f","text":"Iron + Folic + B12 blend"},{"icon":"\ud83d\udc9b","text":"Boosts women''s energy"},{"icon":"\ud83d\udee1\ufe0f","text":"Helps with anaemia"}],"faq":[{"q":"Will it cause constipation?","a":"Some iron supplements can. Drink plenty of water and eat fibre-rich foods to ease this."},{"q":"Is it safe in pregnancy?","a":"Iron supplements are commonly prescribed in pregnancy. Confirm dosage with your doctor."},{"q":"Can I take it with calcium?","a":"Separate by at least 2 hours \u2014 calcium reduces iron absorption."}],"usage_tips":"Take with Vitamin C-rich food (orange, lemon) to boost iron absorption. Avoid taking with tea or coffee. Store away from children.","social_proof":""},{"id":"f355fa9a-a2d8-46eb-8bf7-adb257ab89e4","how_to_use":"Take or give the recommended dose as per packaging, or as directed by your physician.","ingredients":"Multi-ingredient formulation; consult the package leaflet for the complete ingredient list and dosing instructions.","key_benefits":[{"icon":"\ud83c\udf3f","text":"Soothes cough and throat irritation"},{"icon":"\ud83d\udee1\ufe0f","text":"Supports respiratory comfort"},{"icon":"\ud83d\udca7","text":"Gentle daily relief"},{"icon":"\ud83d\udcaa","text":"Doctor-recommended formula"}],"faq":[{"q":"Is it safe for children?","a":"Confirm age-appropriate dosing with your paediatrician."},{"q":"Can I take it with other cough medicines?","a":"Always consult your doctor or pharmacist before combining cough remedies."},{"q":"How long until I feel relief?","a":"Many users feel comfort within 1\u20132 days; continue the full course for best results."}],"usage_tips":"Take after meals if it upsets your stomach. Stay well hydrated to support respiratory comfort. Store in a cool dry place.","social_proof":""},{"id":"86b3b60c-011c-42f1-8542-acb871a03a28","how_to_use":"Take one tablet daily with water, or as directed by your physician.","ingredients":"Glucosamine, Chondroitin, MSM, Collagen, Vitamin D3. Multi-ingredient formulation; consult the package leaflet for the complete ingredient list and adult dosing instructions.","key_benefits":[{"icon":"\ud83d\udcaa","text":"Supports joint mobility"},{"icon":"\ud83c\udf3f","text":"Glucosamine + chondroitin blend"},{"icon":"\ud83d\udee1\ufe0f","text":"Helps cartilage health"},{"icon":"\u2728","text":"Daily mobility support"}],"faq":[{"q":"Is it suitable for athletes?","a":"Yes, Flex-4 is often used by active adults to support joint wear and tear."},{"q":"How long until I feel results?","a":"Joint supplements typically take 6\u201312 weeks of consistent use to show benefits."},{"q":"Any side effects?","a":"Generally well tolerated. Consult your doctor if you have shellfish allergies as some glucosamine is shellfish-derived."}],"usage_tips":"Take with meals to reduce stomach upset. Combine with light low-impact exercise for stronger joint benefits. Store in a cool dry place.","social_proof":""},{"id":"adaee694-26ea-485c-89e8-4ea94872fd4a","how_to_use":"Chew one tablet daily, or as directed by your physician.","ingredients":"Folic Acid. Multi-ingredient formulation; consult the package leaflet for the complete ingredient list and adult dosing instructions.","key_benefits":[{"icon":"\ud83d\udc9b","text":"Chewable folic acid"},{"icon":"\ud83c\udf3f","text":"Supports prenatal health"},{"icon":"\ud83d\udcaa","text":"Easy daily dose"},{"icon":"\ud83d\udee1\ufe0f","text":"Doctor-recommended formula"}],"faq":[{"q":"Is it safe in pregnancy?","a":"Folic acid is commonly prescribed during preconception and pregnancy. Confirm dosage with your doctor."},{"q":"Can men take it?","a":"Yes, folic acid supports general health and is sometimes recommended in male fertility plans."},{"q":"Does it taste okay?","a":"Chewable tablets typically have a mild pleasant flavour \u2014 check the leaflet."}],"usage_tips":"Take at the same time daily for consistency. Stay hydrated throughout the day. Store in a cool dry place away from direct sunlight.","social_proof":""},{"id":"f6d81676-1983-4291-b4c1-a5dc6b38901c","how_to_use":"Take as directed on the packaging or by your physician, typically one tablet or sachet daily with water.","ingredients":"Multi-ingredient formulation; consult the package leaflet for the complete ingredient list and adult dosing in